const body = $input.first().json.body || $input.first().json;

const user_id       = body.user_id       || null;

// Accept optional pre-passed context from Onboarding Intake (avoids extra DB fetch)
const business_name         = body.business_name         || null;
const niche                 = body.niche                 || null;
const target_customer       = body.target_customer       || null;
const primary_goal          = body.primary_goal          || null;
const monthly_revenue_range = body.monthly_revenue_range || null;
const biggest_challenge     = body.biggest_challenge     || null;
const website_url           = body.website_url           || null;

if (!user_id) throw new Error('Missing required field: user_id');

const has_context = !!(business_name && niche && target_customer && primary_goal);

return [{
  json: {
    user_id,
    has_context,
    // Pre-passed context (may be null — will be fetched from DB if so)
    prefilled: {
      business_name,
      niche,
      target_customer,
      primary_goal,
      monthly_revenue_range,
      biggest_challenge,
      website_url
    },
    now: new Date().toISOString()
  }
}];

// Context was passed directly — no DB fetch needed
const origin = $input.first().json;
const p = origin.prefilled;

return [{
  json: {
    user_id:               origin.user_id,
    now:                   origin.now,
    business_name:         p.business_name,
    niche:                 p.niche,
    target_customer:       p.target_customer,
    primary_goal:          p.primary_goal,
    monthly_revenue_range: p.monthly_revenue_range,
    biggest_challenge:     p.biggest_challenge,
    website_url:           p.website_url
  }
}];

const fetchResult = $input.first().json;
const origin = $('Parse & Validate').first().json;

const record = Array.isArray(fetchResult) ? fetchResult[0] : fetchResult;

if (!record || !record.user_id) {
  throw new Error(`No onboarding_responses found for user_id: ${origin.user_id}. Run Onboarding Intake Capture first.`);
}

return [{
  json: {
    user_id:               origin.user_id,
    now:                   origin.now,
    business_name:         record.business_name,
    niche:                 record.niche,
    target_customer:       record.target_customer,
    primary_goal:          record.primary_goal,
    monthly_revenue_range: record.monthly_revenue_range,
    biggest_challenge:     record.biggest_challenge,
    website_url:           record.website_url || null
  }
}];

// Merge both paths (pre-passed context OR DB fetch) into single shape
const items = $input.all();
if (!items || items.length === 0) throw new Error('No onboarding data available to build AI prompt');

const d = items[0].json;

const websiteLine = d.website_url ? `\n- Website: ${d.website_url}` : '';

const userMessage = `Here is the business profile for this Nova OPS user. Generate their operator config:

- Business Name: ${d.business_name}
- Niche / Industry: ${d.niche}
- Target Customer: ${d.target_customer}
- Primary Goal with Nova OPS: ${d.primary_goal}
- Monthly Revenue Range: ${d.monthly_revenue_range}
- Biggest Challenge: ${d.biggest_challenge}${websiteLine}

Respond ONLY with a valid JSON object — no markdown, no backticks, no explanation. Use this exact schema:
{
  "operator_name": "<business_name>-based operator name, 2-4 words>",
  "operator_tone": "<professional|casual|aggressive>",
  "primary_niche": "<1 sentence>",
  "target_customer_profile": "<2-3 sentences describing the ICP>",
  "top_3_pain_points": ["<pain 1>", "<pain 2>", "<pain 3>"],
  "recommended_tools": ["launchpad_tool_X", "launchpad_tool_Y", "launchpad_tool_Z"],
  "gtm_strategy_summary": "<exactly 2 sentences>",
  "brand_voice_keywords": ["<word1>", "<word2>", "<word3>", "<word4>", "<word5>"]
}`;

return [{
  json: {
    ...d,
    user_message: userMessage
  }
}];

