const claudeResponse = $input.first().json;
const origin = $('Merge Context + Build Claude Prompt').first().json;

// Extract text content from Claude response
const content = claudeResponse?.content;
if (!content || !Array.isArray(content) || content.length === 0) {
  throw new Error('Claude API returned no content. Check API key and model availability.');
}

const rawText = content
  .filter(block => block.type === 'text')
  .map(block => block.text)
  .join('')
  .trim();

if (!rawText) {
  throw new Error('Claude response contained no text blocks.');
}

// Strip any accidental markdown fences (defensive)
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

// Parse JSON
let config;
try {
  config = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Claude returned invalid JSON. Parse error: ${e.message}. Raw: ${cleaned.substring(0, 300)}`);
}

// Validate required keys
const requiredKeys = [
  'operator_name',
  'operator_tone',
  'primary_niche',
  'target_customer_profile',
  'top_3_pain_points',
  'recommended_tools',
  'gtm_strategy_summary',
  'brand_voice_keywords'
];
const missingKeys = requiredKeys.filter(k => !(k in config));
if (missingKeys.length > 0) {
  throw new Error(`Claude response missing required keys: ${missingKeys.join(', ')}`);
}

// Validate arrays
if (!Array.isArray(config.top_3_pain_points) || config.top_3_pain_points.length === 0) {
  throw new Error('top_3_pain_points must be a non-empty array');
}
if (!Array.isArray(config.recommended_tools) || config.recommended_tools.length === 0) {
  throw new Error('recommended_tools must be a non-empty array');
}
if (!Array.isArray(config.brand_voice_keywords) || config.brand_voice_keywords.length === 0) {
  throw new Error('brand_voice_keywords must be a non-empty array');
}

// Validate operator_tone
const validTones = ['professional', 'casual', 'aggressive'];
if (!validTones.includes(config.operator_tone)) {
  config.operator_tone = 'professional'; // safe default
}

// Validate recommended_tools are valid launchpad IDs
const validTools = Array.from({length: 10}, (_, i) => `launchpad_tool_${i + 1}`);
const validatedTools = config.recommended_tools.filter(t => validTools.includes(t));
if (validatedTools.length === 0) {
  validatedTools.push('launchpad_tool_1'); // fallback
}
config.recommended_tools = validatedTools;

return [{
  json: {
    user_id: origin.user_id,
    now: origin.now,
    config
  }
}];

const insertResult = $input.first().json;
const origin = $('Parse & Validate Claude JSON').first().json;

const record = Array.isArray(insertResult) ? insertResult[0] : insertResult;

if (!record || !record.user_id) {
  throw new Error(`ai_operator_configs INSERT returned no data for user_id: ${origin.user_id}. Check Supabase schema and RLS.`);
}

return [{
  json: {
    user_id: origin.user_id,
    now: origin.now,
    config: origin.config,
    config_id: record.id || null
  }
}];

const triggerResult = $input.first().json;
const origin = $('Confirm Config Saved').first().json;

const dashboard_triggered = !triggerResult?.error;

return [{
  json: {
    ...origin,
    dashboard_triggered
  }
}];
